import{_ as i,C as d,o as a,c as s,a4 as t,b as l,w as o,a as c,E as n,a5 as u}from"./chunks/framework.4M7SpZrd.js";const A=JSON.parse('{"title":"Milvus Vector DB","description":"","frontmatter":{},"headers":[],"relativePath":"arquitetura/milvus.md","filePath":"arquitetura/milvus.md"}'),h={name:"arquitetura/milvus.md"};function m(p,e,b,f,_,g){const r=d("Mermaid");return a(),s("div",null,[e[1]||(e[1]=t('<h1 id="milvus-vector-db" tabindex="-1">Milvus Vector DB <a class="header-anchor" href="#milvus-vector-db" aria-label="Permalink to &quot;Milvus Vector DB&quot;">​</a></h1><h2 id="visao-geral" tabindex="-1">Visao Geral <a class="header-anchor" href="#visao-geral" aria-label="Permalink to &quot;Visao Geral&quot;">​</a></h2><p>Milvus e o banco vetorial usado para busca de similaridade facial no Kubex (FaceID: Face Recognition). Armazena embeddings de 512 dimensoes gerados pelo InsightFace AntelopeV2.</p><h2 id="infraestrutura-docker" tabindex="-1">Infraestrutura Docker <a class="header-anchor" href="#infraestrutura-docker" aria-label="Permalink to &quot;Infraestrutura Docker&quot;">​</a></h2><p>Tres servicos no docker-compose:</p><table tabindex="0"><thead><tr><th>Servico</th><th>Imagem</th><th>Funcao</th><th>Porta</th></tr></thead><tbody><tr><td>etcd</td><td>quay.io/coreos/etcd</td><td>Metadados e coordenacao</td><td>2379</td></tr><tr><td>minio</td><td>minio/minio</td><td>Armazenamento S3 (logs e indices)</td><td>9000/9001</td></tr><tr><td>milvus</td><td>milvusdb/milvus:v2.4.0</td><td>Banco vetorial</td><td>19530</td></tr></tbody></table><p>Milvus depende de etcd (metadata store) e minio (object storage).</p><h2 id="collection-kubex-face-embeddings" tabindex="-1">Collection: kubex_face_embeddings <a class="header-anchor" href="#collection-kubex-face-embeddings" aria-label="Permalink to &quot;Collection: kubex_face_embeddings&quot;">​</a></h2><h3 id="schema" tabindex="-1">Schema <a class="header-anchor" href="#schema" aria-label="Permalink to &quot;Schema&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Campo</th><th>Tipo</th><th>Descricao</th></tr></thead><tbody><tr><td>id</td><td>INT64</td><td>PK auto-increment</td></tr><tr><td>user_id</td><td>INT64</td><td>creator_id do criador</td></tr><tr><td>embedding</td><td>FLOAT_VECTOR (512)</td><td>InsightFace AntelopeV2 embedding</td></tr><tr><td>ts</td><td>INT64</td><td>Unix timestamp em ms (auditoria)</td></tr></tbody></table><h3 id="index" tabindex="-1">Index <a class="header-anchor" href="#index" aria-label="Permalink to &quot;Index&quot;">​</a></h3><ul><li>Tipo: HNSW</li><li>Parametros: M=16, efConstruction=200</li><li>Metrica: COSINE</li><li>Search params: ef=200</li></ul><h3 id="threshold" tabindex="-1">Threshold <a class="header-anchor" href="#threshold" aria-label="Permalink to &quot;Threshold&quot;">​</a></h3><ul><li>COSINE_THRESHOLD = 0.6 (score minimo para match)</li><li>Scores de 0 a 1 (1 = identico)</li></ul><h2 id="wrapper-facemilvus" tabindex="-1">Wrapper: FaceMilvus <a class="header-anchor" href="#wrapper-facemilvus" aria-label="Permalink to &quot;Wrapper: FaceMilvus&quot;">​</a></h2><p>Arquivo: <code>app/engines/face_milvus.py</code></p><table tabindex="0"><thead><tr><th>Metodo</th><th>Descricao</th></tr></thead><tbody><tr><td>connect()</td><td>Conecta ao Milvus, cria collection se nao existir</td></tr><tr><td>insert(user_id, embedding)</td><td>Insere embedding de um criador</td></tr><tr><td>search(embedding, limit, threshold)</td><td>Busca similaridade, retorna user_id + score &gt;= threshold</td></tr><tr><td>delete_by_user(creator_id)</td><td>Remove todos embeddings de um criador (LGPD)</td></tr></tbody></table><ul><li>Singleton via get_face_milvus() (instanciado apenas no face-worker)</li><li>Graceful degradation: se pymilvus nao instalado ou Milvus offline, retorna [] sem erro</li><li>Thread-safe via pymilvus MilvusClient</li></ul><h2 id="fluxo-de-dados" tabindex="-1">Fluxo de Dados <a class="header-anchor" href="#fluxo-de-dados" aria-label="Permalink to &quot;Fluxo de Dados&quot;">​</a></h2>',19)),(a(),l(u,null,{default:o(()=>[n(r,{id:"mermaid-259",class:"mermaid",graph:"sequenceDiagram%0A%20%20%20%20participant%20U%20as%20Selfie%20Upload%0A%20%20%20%20participant%20API%20as%20FastAPI%0A%20%20%20%20participant%20Q%20as%20celery_face%20queue%0A%20%20%20%20participant%20W%20as%20face-worker%0A%20%20%20%20participant%20IF%20as%20InsightFace%0A%20%20%20%20participant%20PG%20as%20PostgreSQL%0A%20%20%20%20participant%20MV%20as%20Milvus%0A%0A%20%20%20%20U-%3E%3EAPI%3A%20POST%20selfie%0A%20%20%20%20API-%3E%3EQ%3A%20enqueue%20task%0A%20%20%20%20Q-%3E%3EW%3A%20consume%0A%20%20%20%20W-%3E%3EIF%3A%20detecta%20rosto%0A%20%20%20%20IF--%3E%3EW%3A%20embedding%20512-d%0A%20%20%20%20W-%3E%3EPG%3A%20AES-256-GCM%20encrypt%20%E2%86%92%20creator_embeddings%0A%20%20%20%20W-%3E%3EMV%3A%20plaintext%20embedding%20%E2%86%92%20insert%20(para%20busca)%0A%0A%20%20%20%20Note%20over%20W%2CMV%3A%20Busca%20de%20similaridade%0A%20%20%20%20W-%3E%3EIF%3A%20nova%20imagem%20%E2%86%92%20embedding%0A%20%20%20%20W-%3E%3EMV%3A%20search(embedding)%0A%20%20%20%20MV--%3E%3EW%3A%20matches%20(user_id%20%2B%20score)%0A"})]),fallback:o(()=>[...e[0]||(e[0]=[c(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=t('<h2 id="performance" tabindex="-1">Performance <a class="header-anchor" href="#performance" aria-label="Permalink to &quot;Performance&quot;">​</a></h2><p>Benchmarks (de overview.md):</p><ul><li>Face detection + embedding (CPU): ~300ms</li><li>Milvus search 1k embeddings: ~2ms</li><li>Milvus search 100k embeddings: ~10ms</li></ul><h2 id="recursos-adicionais" tabindex="-1">Recursos Adicionais <a class="header-anchor" href="#recursos-adicionais" aria-label="Permalink to &quot;Recursos Adicionais&quot;">​</a></h2><h3 id="parametro-hnsw-ef-configuravel" tabindex="-1">Parametro HNSW ef configuravel <a class="header-anchor" href="#parametro-hnsw-ef-configuravel" aria-label="Permalink to &quot;Parametro HNSW ef configuravel&quot;">​</a></h3><p>O parametro <code>ef</code> de busca HNSW e configuravel via <code>MILVUS_SEARCH_EF</code> em <code>app/config.py</code> (default 200). Valores maiores aumentam recall ao custo de latencia.</p><h3 id="optout-collection" tabindex="-1">OptOut Collection <a class="header-anchor" href="#optout-collection" aria-label="Permalink to &quot;OptOut Collection&quot;">​</a></h3><p>Collection <code>kubex_face_optouts</code> armazena embeddings de faces que solicitaram remocao:</p><ul><li><strong>Schema:</strong> optout_id (PK), embedding (FLOAT_VECTOR 512), email_hash, created_at</li><li><strong>Index:</strong> HNSW (M=16, efConstruction=200, COSINE)</li></ul><h3 id="batch-insert" tabindex="-1">Batch Insert <a class="header-anchor" href="#batch-insert" aria-label="Permalink to &quot;Batch Insert&quot;">​</a></h3><p>Metodo <code>batch_insert_faces()</code> permite insercao em lote, reduzindo round-trips gRPC ao Milvus durante operacoes de bulk crawling.</p><h3 id="partitions" tabindex="-1">Partitions <a class="header-anchor" href="#partitions" aria-label="Permalink to &quot;Partitions&quot;">​</a></h3><p>A collection <code>kubex_web_faces</code> usa 7 particoes nomeadas para segmentar dados por categoria de site:</p><ul><li><code>tube_sites</code>, <code>leak_sites</code>, <code>escort_sites</code>, <code>forums</code>, <code>imageboards</code>, <code>social_media</code>, <code>general_web</code></li></ul><h3 id="optoutcache" tabindex="-1">OptOutCache <a class="header-anchor" href="#optoutcache" aria-label="Permalink to &quot;OptOutCache&quot;">​</a></h3><p>Cache Redis que armazena embeddings de opt-out em memoria, eliminando round-trip ao Milvus por face durante ingestao. Refresh a cada 1h via Celery Beat (<code>face_index.refresh_optout_cache</code>).</p><h2 id="lgpd" tabindex="-1">LGPD <a class="header-anchor" href="#lgpd" aria-label="Permalink to &quot;LGPD&quot;">​</a></h2><ul><li>Nenhum dado demografico armazenado (sem genero, idade, landmarks)</li><li>delete_by_user() remove todos os vetores ao deletar usuario</li><li>Embedding no PostgreSQL e cifrado; no Milvus e plaintext (necessario para busca vetorial)</li></ul>',18))])}const P=i(h,[["render",m]]);export{A as __pageData,P as default};
